    name: "Gelgelar Free Port",
    system: "Gelgelar",
    star: "Gelgelar",
    sector: "Elrood Sector",
    type: "Starport settlement (planetary surface)",
    temperature: "Cool",
    atmosphere: "Type II (breath mask suggested)",
